// Prepara un row de historial de proyecto. Cliente envía:
// { proyecto_id, usuario:{id,nombre,rol}, accion, seccion_nombre?,
//   tarea_id?, tarea_nombre?, descripcion?, cambios?, metadata? }
const ACCIONES_VALIDAS = new Set([
  'tarea_completada','tarea_reabierta','tarea_eliminada','tarea_movida',
  'tarea_anadida','tarea_actualizada',
  'subtarea_completada','subtarea_reabierta','subtarea_eliminada',
  'subtarea_anadida','subtarea_actualizada','subtarea_agendada','subtarea_desagendada',
  'show_asignado','show_noshow','show_limpiado',
  'proyecto_creado','proyecto_pausado','proyecto_reanudado',
  'proyecto_completado','proyecto_eliminado','proyecto_actualizado',
  'anotacion_added','anotacion_updated','anotacion_deleted',
  'adjunto_add','adjunto_remove',
  'contacto_added','contacto_removed',
  'otro'
]);
const body = ($input.first().json.body) || {};
if (!body.proyecto_id) throw new Error('proyecto_id es obligatorio');
const accion = String(body.accion || '').toLowerCase();
if (!ACCIONES_VALIDAS.has(accion)) throw new Error('accion inválida: ' + body.accion);
const u = body.usuario || {};
const rolValidado = ['admin','user','sistema'].includes(u.rol) ? u.rol : 'user';
const row = {
  proyecto_id:    body.proyecto_id,
  usuario_id:     u.id || null,
  usuario_nombre: (u.nombre || u.username || '').slice(0, 120) || null,
  usuario_rol:    rolValidado,
  accion:         accion,
  seccion_nombre: body.seccion_nombre ? String(body.seccion_nombre).slice(0, 200) : null,
  tarea_id:       body.tarea_id ? String(body.tarea_id).slice(0, 64) : null,
  tarea_nombre:   body.tarea_nombre ? String(body.tarea_nombre).slice(0, 240) : null,
  descripcion:    body.descripcion ? String(body.descripcion).slice(0, 500) : null,
  cambios:        JSON.stringify(body.cambios  || {}),
  metadata:       JSON.stringify(body.metadata || {})
};
return [{ json: row }];

const input = $input.all();
let id = null;
const errores = [];
for (const it of input) {
  const j = (it && it.json) ? it.json : it;
  if (!j) continue;
  if (j.error) { errores.push(String(j.error.message || j.error.code || j.error)); continue; }
  if (j.id) id = j.id;
}
return [{ json: { success: !!id, id, errores } }];

const q = ($input.first().json && $input.first().json.query) || {};
const proyectoId = String(q.proyectoId || q.proyecto_id || '').trim();
if (!proyectoId) throw new Error('Se requiere proyectoId en query');
const limit = Math.min(Math.max(parseInt(q.limit, 10) || 200, 1), 500);
const offset = Math.max(parseInt(q.offset, 10) || 0, 0);
return [{ json: { proyectoId, limit, offset } }];

function parseJson(v, fb){if(v==null)return fb;if(Array.isArray(v)||typeof v==='object')return v;if(typeof v==='string'){try{return JSON.parse(v);}catch(_){return fb;}}return fb;}
const { limit, offset } = $('Preparar GET Proy Historial').first().json;
const rows = $input.all().map(i => i.json).filter(r => r && r.id);
for (const r of rows) { r.cambios = parseJson(r.cambios, {}); r.metadata = parseJson(r.metadata, {}); }
return [{ json: { historial: rows, paging: { limit, offset, count: rows.length, has_more: rows.length >= limit } } }];
